 1	import * as React from 'react';
 2	import { PrometheusUtilizationItem } from '@odf/shared/dashboards/utilization-card/prometheus-utilization-item';
 3	import {
 4	  NodeQueries,
 5	  getUtilizationQueries,
 6	  getResourceQuotaQueries,
 7	} from '@odf/shared/queries/node';
 8	import { NodeKind } from '@odf/shared/types';
 9	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
10	import {
11	  getNodeAddresses,
12	  humanizeCpuCores,
13	  humanizeBinaryBytes,
14	} from '@odf/shared/utils';
15	import { UtilizationBody } from '@openshift-console/dynamic-plugin-sdk-internal';
16	import { ByteDataTypes } from '@openshift-console/dynamic-plugin-sdk-internal/lib/api/internal-types';
17	import { Card, CardHeader, CardTitle } from '@patternfly/react-core';
18	import './node-observe.scss';
19	
20	type NodeObserveProps = {
21	  resource: NodeKind;
22	  odfNamespace?: string;
23	};
24	
25	export const NodeObserve: React.FC<NodeObserveProps> = ({ resource: node }) => {
26	  const { t } = useCustomTranslation();
27	
28	  const nodeName = node.metadata.name;
29	  const nodeIP = getNodeAddresses(node).find(
30	    (addr) => addr.type === 'InternalIP'
31	  )?.address;
32	
33	  const [utilizationQueries, resourceQuotaQueries] = [
34	    getUtilizationQueries(nodeName, nodeIP),
35	    getResourceQuotaQueries(nodeName),
36	  ];
37	
38	  return (
39	    <Card className="node-observe-tab" data-test-id="node-observe-tab">
40	      <CardHeader>
41	        <CardTitle>{t('Metrics')}</CardTitle>
42	      </CardHeader>
43	      <UtilizationBody>
44	        <PrometheusUtilizationItem
45	          title={t('CPU usage')}
46	          humanizeValue={humanizeCpuCores}
47	          utilizationQuery={utilizationQueries[NodeQueries.CPU_USAGE]}
48	          totalQuery={utilizationQueries[NodeQueries.CPU_TOTAL]}
49	          limitQuery={resourceQuotaQueries[NodeQueries.POD_RESOURCE_LIMIT_CPU]}
50	          requestQuery={
51	            resourceQuotaQueries[NodeQueries.POD_RESOURCE_REQUEST_CPU]
52	          }
53	        />
54	        <PrometheusUtilizationItem
55	          title={t('Memory')}
56	          humanizeValue={humanizeBinaryBytes}
57	          utilizationQuery={utilizationQueries[NodeQueries.MEMORY_USAGE]}
58	          totalQuery={utilizationQueries[NodeQueries.MEMORY_TOTAL]}
59	          limitQuery={
60	            resourceQuotaQueries[NodeQueries.POD_RESOURCE_LIMIT_MEMORY]
61	          }
62	          requestQuery={
63	            resourceQuotaQueries[NodeQueries.POD_RESOURCE_REQUEST_MEMORY]
64	          }
65	          byteDataType={ByteDataTypes.BinaryBytes}
66	        />
67	      </UtilizationBody>
68	    </Card>
69	  );
70	};

